// Parse page 1 and tag with page number
const html = $input.first().json.content || '';
const companies = [];

const cards = html.split('id="item-card-filter"');
for (let i = 1; i < cards.length; i++) {
  const card = cards[i];
  const nameMatch = card.match(/id="startup-website-link">([^<]+)<\/a><\/h3>/i);
  const urlMatch = card.match(/href="(https:\/\/[^"]+)"[^>]*id="startup-website-link"/i);
  const descMatch = card.match(/What they do:[^<]*<\/b>\s*<br>([^<]+)<br>/i);
  const empMatch = card.match(/(\d+)-(\d+)\s*employees/i);
  const foundedMatch = card.match(/Founded:\s*(\d{4})/i);
  const fundingMatch = card.match(/\$(\d+)M\s*(Series [A-C]|Seed|Pre-Seed)[^<]*in\s*(\d{4})/i);

  if (nameMatch && urlMatch) {
    companies.push({
      json: {
        company_name: nameMatch[1].trim(),
        company_url: urlMatch[1].replace('?utm_source=topstartups.io', ''),
        description: descMatch ? descMatch[1].trim().replace(/&amp;/g, '&') : '',
        employee_count: empMatch ? Math.round((parseInt(empMatch[1]) + parseInt(empMatch[2])) / 2) : null,
        founded_year: foundedMatch ? parseInt(foundedMatch[1]) : null,
        total_funding: fundingMatch ? `$${fundingMatch[1]}M` : '',
        funding_stage: fundingMatch ? fundingMatch[2] : '',
        source: 'topstartups.io',
        _page: 1
      }
    });
  }
}
console.log('Page 1:', companies.length, 'companies');
return companies;

