// Summary and cleanup
const items = $input.all();
const byPage = {};

items.forEach(item => {
  const p = item.json._page || '?';
  if (!byPage[p]) byPage[p] = [];
  byPage[p].push(item.json.company_name);
});

console.log('=== PAGINATION SUMMARY ===');
console.log('Total companies:', items.length);
Object.keys(byPage).sort().forEach(p => {
  console.log(`Page ${p}: ${byPage[p].length} companies - ${byPage[p].slice(0,3).join(', ')}...`);
});

// Check for duplicates
const names = items.map(i => i.json.company_name);
const unique = [...new Set(names)];
if (names.length !== unique.length) {
  console.log('WARNING: ' + (names.length - unique.length) + ' duplicate companies!');
}

// Remove _page field before pipeline
return items.map(item => {
  const { _page, ...rest } = item.json;
  return { json: rest };
});
